import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";
import Navbar from "../components/Navbar";
import { toast } from "sonner";

export default function Login() {
  const { login } = useAuth();
  const nav = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setBusy(true);
    try {
      await login(email, password);
      toast.success("welcome back");
      nav("/dashboard");
    } catch (err) {
      toast.error(err?.response?.data?.detail || "login failed");
    } finally {
      setBusy(false);
    }
  };

  const googleLogin = () => {
    const redirectUrl = `${window.location.origin}/auth/emergent/callback`;
    window.location.href = `https://auth.emergentagent.com/?redirect_url=${encodeURIComponent(redirectUrl)}`;
  };

  return (
    <div className="min-h-screen bg-black text-white">
      <Navbar floating={false} />
      <div className="max-w-md mx-auto px-6 pt-24 pb-16">
        <h1 className="hero-title text-5xl font-medium mb-2" data-testid="login-title">members login</h1>
        <p className="text-white/60 mb-8 text-sm">sign in to manage your projects and view announcements.</p>

        <button
          onClick={googleLogin}
          data-testid="login-google-btn"
          className="w-full bg-white text-black rounded-full py-3 text-sm font-normal hover:bg-neutral-200 transition-colors mb-3"
        >
          continue with google
        </button>

        <div className="flex items-center gap-3 my-6">
          <div className="h-px flex-1 bg-white/10" />
          <span className="text-xs text-white/40">or with email</span>
          <div className="h-px flex-1 bg-white/10" />
        </div>

        <form onSubmit={submit} className="space-y-3">
          <input
            type="email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="email"
            data-testid="login-email-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <input
            type="password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="password"
            data-testid="login-password-input"
            className="w-full bg-neutral-900/90 border border-white/10 rounded-full px-5 py-3 text-sm text-white placeholder-white/40 focus:outline-none focus:border-white/30"
          />
          <button
            type="submit"
            disabled={busy}
            data-testid="login-submit-btn"
            className="w-full bg-white text-black rounded-full py-3 text-sm font-normal hover:bg-neutral-200 transition-colors disabled:opacity-50"
          >
            {busy ? "signing in..." : "sign in"}
          </button>
        </form>

        <div className="mt-6 text-sm text-white/60 flex items-center justify-between">
          <Link to="/register" data-testid="login-register-link" className="hover:text-white transition-colors">create account</Link>
          <Link to="/admin/login" data-testid="login-admin-link" className="hover:text-white transition-colors">admin login →</Link>
        </div>
      </div>
    </div>
  );
}
